            "level": "INFO",
            "handlers": ["file"],
            "propagate": "no"
        }
    }
}
```

And then run Ansible (or a Python script that uses pypsrp) with the environment variable `PYPSRP_LOG_CFG=/path/to/file/above.json`. The file `pypsrp.log` would only contain `INFO` entries that come under the `pypsrp*` namespace. Any other libraries like requests are not in this log. I can change that by changing the values under `logger` to include the other libraries or just `*` but as I am saying this is entirely up to the end user to decide what they want.

